const iE=[{id:1,slug:"1",title:"Latest Publication: VR Study on Flood Risk Response",desc:"Our latest research published in IJDRR leverages Virtual Reality to simulate urban floods, uncovering how human responses shift across different contexts.",detail:"The study reveals that people are significantly more sensitive to flood risks when in a car than on the street, especially at night. It also highlights how self-efficacy, warning sirens, and socioeconomic factors critically shape emergency evacuation behaviors.",externalLink:"https://doi.org/10.1016/j.ijdrr.2025.105956"},{id:2,slug:"codesignai",title:"Tools Release: CoDesignAI Collaborative Platform",desc:"CoDesignAI is a web-based collaborative platform that uses multi-agent AI to support participatory urban design.",detail:"The system integrates conversational AI with Google Maps and Street View to help multiple users explore real-world urban contexts, discuss ideas, and generate visual design concepts together. By enabling iterative discussion and AI-assisted visualization, CoDesignAI aims to make early-stage urban design more open, collaborative, and accessible to diverse participants."},{id:3,slug:"vrgreencallforusers",title:"On-going User Test: Virtual Therapy to Urban Stress",desc:"Virtual Therapy to Urban Stress is an immersive research project that uses Virtual Reality (VR) and multimodal physiological sensors to evaluate how context-specific urban greenery impacts human stress and well-being. ",detail:"The study integrates AI-modified 360° visual stimuli with EEG, EDA, and psychological surveys to track real-time cognitive and physiological responses across diverse urban settings, such as parks, waterfronts, and traffic corridors. By bridging neuroscience and urban design, the project aims to provide evidence-based guidelines for effective green space planning and validate VR as an accessible therapeutic tool for public health."}],Os={1:{type:"image",src:uc},2:{type:"video",src:yg},3:{type:"image",src:e1}}